124	/// Format a duration as a human-readable string, Cargo-style.
125	pub(super) fn elapsed(duration: Duration) -> String {
126	    let secs = duration.as_secs();
127	    let ms = duration.subsec_millis();
128	
129	    if secs >= 60 {
130	        format!("{}m {:02}s", secs / 60, secs % 60)
131	    } else if secs > 0 {
132	        format!("{}.{:02}s", secs, duration.subsec_nanos() / 10_000_000)
133	    } else if ms > 0 {
134	        format!("{ms}ms")
135	    } else {
136	        format!("0.{:02}ms", duration.subsec_nanos() / 10_000)
137	    }
138	}
