use std::fmt::Write;

use anyhow::Result;
use diskus::DiskUsage;

use crate::commands::{ExitStatus, human_readable_bytes};
use crate::printer::Printer;
use uv_cache::{Cache, CacheBucket};

/// Display per-bucket cache statistics.
pub(crate) fn cache_stats(
    cache: &Cache,
    human_readable: bool,
    printer: Printer,
) -> Result<ExitStatus> {
    let mut total_bytes: u64 = 0;

    for bucket in CacheBucket::iter() {
        let bucket_path = cache.bucket(bucket);
        let bucket_bytes = if bucket_path.exists() {
            let disk_usage = DiskUsage::new(vec![bucket_path]);
            disk_usage.count_ignoring_errors()
        } else {
            0
        };

        total_bytes += bucket_bytes;

        if human_readable {
            let (bytes, unit) = human_readable_bytes(bucket_bytes);
            writeln!(printer.stdout_important(), "{bucket}: {bytes:.1}{unit}")?;
        } else {
            writeln!(printer.stdout_important(), "{bucket}: {bucket_bytes}")?;
        }
    }

    if human_readable {
        let (bytes, unit) = human_readable_bytes(total_bytes);
        writeln!(printer.stdout_important(), "total: {bytes:.1}{unit}")?;
    } else {
        writeln!(printer.stdout_important(), "total: {total_bytes}")?;
    }

    Ok(ExitStatus::Success)
}

